const listHRCases = `-- name: ListHRCases :many
SELECT
    c.id, c.tenant_id, c.case_number, c.category_id, c.case_type, c.title, c.description, c.confidentiality_level, c.requester_user_id, c.subject_employee_user_id, c.owner_user_id, c.owner_role, c.status, c.priority, c.source_channel, c.first_response_due_at, c.first_responded_at, c.due_at, c.resolved_at, c.closed_at, c.escalated_at, c.escalation_level, c.last_activity_at, c.resolution_summary, c.inactive, c.created_at, c.created_by, c.updated_at, c.updated_by,
    cc.name AS category_name,
    cc.code AS category_code,
    NULL::text AS requester_email,
    NULL::text AS subject_email,
    NULL::text AS owner_email,
    COALESCE(comment_counts.comment_count, 0)::int AS comment_count,
    COALESCE(attachment_counts.attachment_count, 0)::int AS attachment_count
FROM hrms.hr_cases c
LEFT JOIN hrms.hr_case_categories cc ON cc.tenant_id = c.tenant_id AND cc.id = c.category_id AND NOT cc.inactive
LEFT JOIN LATERAL (
    SELECT COUNT(*) AS comment_count
    FROM hrms.hr_case_comments hcc
    WHERE hcc.tenant_id = c.tenant_id AND hcc.case_id = c.id AND NOT hcc.inactive
) comment_counts ON TRUE
LEFT JOIN LATERAL (
    SELECT COUNT(*) AS attachment_count
    FROM hrms.hr_case_attachments hca
    WHERE hca.tenant_id = c.tenant_id AND hca.case_id = c.id AND NOT hca.inactive
) attachment_counts ON TRUE
WHERE c.tenant_id = $1
  AND ($2::text IS NULL OR c.status = $2::text)
  AND ($3::text IS NULL OR c.priority = $3::text)
  AND ($4::uuid IS NULL OR c.category_id = $4::uuid)
  AND ($5::uuid IS NULL OR c.requester_user_id = $5::uuid)
  AND ($6::uuid IS NULL OR c.subject_employee_user_id = $6::uuid)
  AND ($7::uuid IS NULL OR c.owner_user_id = $7::uuid)
  AND ($8::text IS NULL OR c.confidentiality_level = $8::text)
  AND (
      $9::text IS NULL
      OR c.case_number ILIKE '%' || $9::text || '%'
      OR c.title ILIKE '%' || $9::text || '%'
      OR c.description ILIKE '%' || $9::text || '%'
      OR c.requester_user_id::text ILIKE '%' || $9::text || '%'
      OR c.subject_employee_user_id::text ILIKE '%' || $9::text || '%'
  )
  AND NOT c.inactive
ORDER BY
  CASE c.priority WHEN 'urgent' THEN 1 WHEN 'high' THEN 2 WHEN 'normal' THEN 3 ELSE 4 END,
  CASE c.status WHEN 'new' THEN 1 WHEN 'open' THEN 2 WHEN 'escalated' THEN 3 WHEN 'in_progress' THEN 4 ELSE 5 END,
  c.due_at ASC NULLS LAST,
  c.last_activity_at DESC
LIMIT $11 OFFSET $10
`

